using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Extract embedded source files from the binlog
Console.WriteLine("=== EMBEDDED FILES ===");
if (build.SourceFilesArchive != null)
{
    foreach (var entry in build.SourceFilesArchive)
    {
        Console.WriteLine($"  {entry.Key}");
    }
}
else
{
    Console.WriteLine("  No embedded source archive found");
}

// Check for project references in item groups
Console.WriteLine();
Console.WriteLine("=== PROJECT ITEMS (PackageReference & ProjectReference) ===");
build.VisitAllChildren<Item>(item => {
    var parent = item.GetNearestParent<Folder>();
    if (parent != null && (parent.Name == "PackageReference" || parent.Name == "ProjectReference"))
    {
        var project = item.GetNearestParent<Project>();
        Console.WriteLine($"  [{project?.Name}] {parent.Name}: {item.Name}");
    }
});

// Show the Api project's dependency chain to understand cascading
Console.WriteLine();
Console.WriteLine("=== DEPENDENCY ANALYSIS ===");
var projectErrors = new Dictionary<string, List<string>>();
build.VisitAllChildren<Error>(e => {
    var proj = e.GetNearestParent<Project>()?.Name ?? "unknown";
    if (!projectErrors.ContainsKey(proj))
        projectErrors[proj] = new List<string>();
    projectErrors[proj].Add($"{e.Code}: {e.Text} ({e.File}:{e.LineNumber})");
});

foreach (var kv in projectErrors)
{
    Console.WriteLine($"\nProject with errors: {kv.Key}");
    foreach (var err in kv.Value)
        Console.WriteLine($"  {err}");
}

// Check which projects failed vs succeeded
Console.WriteLine();
Console.WriteLine("=== TARGET RESULTS ===");
build.VisitAllChildren<Target>(t => {
    if (t.Name == "CoreCompile" || t.Name == "Build" || t.Name == "ResolvePackageAssets")
    {
        var proj = t.GetNearestParent<Project>()?.Name ?? "unknown";
        var hasErr = false;
        t.VisitAllChildren<Error>(e => { hasErr = true; });
        if (hasErr || t.Name == "Build")
        {
            // Only show targets with errors or Build targets
            if (hasErr)
                Console.WriteLine($"  {proj} -> {t.Name} FAILED");
        }
    }
});
EOF

