build.VisitAllChildren<Project>(p => {
    // Skip solution-level
    if (p.Name.EndsWith(".sln")) return;

    var hasErrors = false;
    var errors = new System.Collections.Generic.List<string>();
    p.VisitAllChildren<Error>(e => { 
        hasErrors = true;
        errors.Add($"    {e.Code}: {e.Text}");
    });

    // Check for project references within this project's items
    var projRefs = new System.Collections.Generic.List<string>();
    var pkgRefs = new System.Collections.Generic.List<string>();
    p.VisitAllChildren<Item>(item => {
        var folder = item.GetNearestParent<Folder>();
        if (folder?.Name == "ProjectReference" && item.GetNearestParent<Project>() == p)
            projRefs.Add(item.Name);
        if (folder?.Name == "PackageReference" && item.GetNearestParent<Project>() == p)
            pkgRefs.Add(item.Name);
    });

    // Only print projects with the Build target (actual build, not restore)
    var hasBuild = false;
    p.VisitAllChildren<Target>(t => { if (t.Name == "CoreCompile") hasBuild = true; });
    if (!hasBuild) return;

    Console.WriteLine($"\nProject: {p.Name}");
    Console.WriteLine($"  Status: {(hasErrors ? "FAILED" : "OK")}");
    if (projRefs.Any())
        Console.WriteLine($"  ProjectReferences: {string.Join(", ", projRefs.Distinct())}");
    if (pkgRefs.Any())
        Console.WriteLine($"  PackageReferences: {string.Join(", ", pkgRefs.Distinct())}");
    foreach (var e in errors)
        Console.WriteLine(e);
});

// Check if Api project was skipped or had dependency failures
